#include <vector>
#include <unordered_set>

using namespace std;

class Solution {
public:
    vector<int> splitArray(vector<int>& nums, vector<vector<int>>& queries) {
        vector<int> result;
        unordered_set<int> primes;
        for (int i = 0; i < nums.size(); ++i) {
            if (isPrime(nums[i])) {
                primes.insert(nums[i]);
            }
        }
        for (auto& query : queries) {
            int idx = query[0];
            int val = query[1];
            nums[idx] = val;
            int count = 0;
            for (int i = 0; i < nums.size(); ++i) {
                if (isPrime(nums[i])) {
                    count++;
                }
            }
            result.push_back(count);
        }
        return result;
    }
    bool isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        for (int i = 2; i * i <= num; ++i) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
};
```
efficiency: HIGH
time complexity: O(N*Q*log(N))
space complexity: O(N)
